# Calculate IDCG using the ideal ranking of all expected docs, ordered
# by relevance score from highest to lowest (all equal to 1.0 for the
# binary relevance case). We use len(expected_ids) as the ideal length
# since we can't achieve better than a perfect ranking of all relevant docs.
if relevance_scores is not None:
    ideal_relevances = sorted(
        (relevance_scores.get(doc_id, 1.0) for doc_id in expected_ids),
        reverse=True,
    )
else:
    ideal_relevances = [1.0] * len(expected_ids)

idcg = sum(
    discounted_gain(rel=rel, i=i, mode=mode)
    for i, rel in enumerate(ideal_relevances, start=1)
)

